<span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">├─ north: uncertain(Distributions.Gamma{Float64}(α=2.0, θ=1.0); shape = pool(:district, uncertain(Distributions.LogNormal{Float64}(μ=0.0, σ=1.0); mu = Distributions.Normal{Float64}(μ=0.0, σ=1.0), sigma = Truncated(Distributions.Normal{Float64}(μ=0.0, σ=1.0); lower=0.0))))</span></span>
